import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicFiveDays() {
        // [3,1,2,5,4] limit=6:
        //   [3]=3, [3,1]=4, [3,1,2]=6 (len 3) — valid, max so far 3
        //   [3,1,2,5]=11 > 6 → shrink to [5] (len 1)
        //   [5,4]=9 > 6 → shrink to [4] (len 1)
        //   Answer: 3
        assertEquals(3, new Solution().longestStreakUnderLimit(
                new int[]{3, 1, 2, 5, 4}, 6));
    }

    @Test
    void emptyArray() {
        assertEquals(0, new Solution().longestStreakUnderLimit(new int[]{}, 10));
    }

    @Test
    void allZerosLimitZero() {
        // All zeros, limit=0: entire array qualifies (sum always 0 <= 0)
        assertEquals(3, new Solution().longestStreakUnderLimit(
                new int[]{0, 0, 0}, 0));
    }

    @Test
    void everyDayExceedsLimit() {
        // Each payment alone exceeds the limit — no valid window
        assertEquals(0, new Solution().longestStreakUnderLimit(
                new int[]{10, 10}, 5));
    }

    @Test
    void ascendingPayments() {
        // [1,2,3,4,5] limit=3: longest valid run is [1,2] sum=3, length 2
        assertEquals(2, new Solution().longestStreakUnderLimit(
                new int[]{1, 2, 3, 4, 5}, 3));
    }

    @Test
    void singleElementMeetsLimit() {
        // One payment that exactly meets the limit
        assertEquals(1, new Solution().longestStreakUnderLimit(
                new int[]{7}, 7));
    }

    @Test
    void allDaysMeetLimit() {
        // All payments well below limit — whole array is the answer
        assertEquals(5, new Solution().longestStreakUnderLimit(
                new int[]{1, 1, 1, 1, 1}, 100));
    }
}
